// Code Generated by Sidekick is for learning and experimentation purposes only.
/**
 * Unified Chat Interface with OpenAI Voice Support
 * Fixed version with defensive API checks
 */

class UnifiedChatInterface extends ChatInterface {
    constructor() {
        super();
        
        // Voice-specific properties
        this.voiceApiBaseUrl = '/api/voice';
        this.mediaRecorder = null;
        this.audioChunks = [];
        this.isRecording = false;
        this.autoSpeak = false;
        this.currentAudio = null;
        this.selectedVoice = 'nova';
        
        // ✅ Store reference to media API
        this.mediaDevicesAPI = null;
        
        // Voice DOM elements
        this.micBtn = document.getElementById('mic-btn');
        this.speakerBtn = document.getElementById('speaker-btn');
        this.voiceStatusText = document.getElementById('voice-status-text');
        this.voiceStatusSubtext = document.getElementById('voice-status-subtext');
        this.waveform = document.getElementById('waveform');
        
        // Initialize voice features if elements exist
        if (this.micBtn) {
            this.initVoiceFeatures();
        }
        
        console.log('[UnifiedChat] Voice features initialized');
    }
    
    initVoiceFeatures() {
        console.log('[Voice] Initializing voice features...');
        
        // ✅ Verify and store API reference
        if (this.verifyMediaAPI()) {
            this.checkExistingPermissions();
        } else {
            console.error('[Voice] Media API not available during init');
            if (this.micBtn) this.micBtn.disabled = true;
        }
    }
    
    // ✅ NEW: Verify media API is available
    verifyMediaAPI() {
        console.log('[Voice] Verifying Media API...');
        
        // Check if navigator exists
        if (typeof navigator === 'undefined') {
            console.error('[Voice] ❌ navigator is undefined');
            return false;
        }
        
        // Check if mediaDevices exists
        if (!navigator.mediaDevices) {
            console.error('[Voice] ❌ navigator.mediaDevices is undefined');
            console.log('[Voice] Location:', window.location.href);
            console.log('[Voice] Protocol:', window.location.protocol);
            console.log('[Voice] Secure context:', window.isSecureContext);
            return false;
        }
        
        // Check if getUserMedia exists
        if (typeof navigator.mediaDevices.getUserMedia !== 'function') {
            console.error('[Voice] ❌ getUserMedia is not a function');
            return false;
        }
        
        // Store reference
        this.mediaDevicesAPI = navigator.mediaDevices;
        
        console.log('[Voice] ✅ Media API verified and stored');
        return true;
    }
    
    // ✅ NEW: Get media API with verification
    getMediaAPI() {
        // Always re-verify on access
        if (!this.mediaDevicesAPI) {
            console.warn('[Voice] API reference lost, re-verifying...');
            this.verifyMediaAPI();
        }
        
        // Double check it's still available
        if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
            console.error('[Voice] ❌ Media API not available at access time');
            return null;
        }
        
        return navigator.mediaDevices;
    }
    
    async checkExistingPermissions() {
        if (!navigator.permissions || !navigator.permissions.query) {
            console.log('[Voice] Permission API not supported');
            return;
        }
        
        try {
            const result = await navigator.permissions.query({ name: 'microphone' });
            console.log(`[Voice] Current microphone permission: ${result.state}`);
            
            if (result.state === 'granted') {
                this.updateMicrophoneStatus('✓ Microphone ready', 'Click to start recording');
            } else if (result.state === 'denied') {
                this.showPermissionDeniedHelp();
            } else {
                this.updateMicrophoneStatus('Click microphone to speak', 'Powered by OpenAI Whisper');
            }
            
            result.addEventListener('change', () => {
                console.log(`[Voice] Permission changed to: ${result.state}`);
                if (result.state === 'granted') {
                    this.updateMicrophoneStatus('✓ Microphone ready', 'Click to start recording');
                } else if (result.state === 'denied') {
                    this.showPermissionDeniedHelp();
                }
            });
            
        } catch (error) {
            console.log('[Voice] Could not query permissions:', error);
        }
    }
    
    showPermissionDeniedHelp() {
        if (this.voiceStatusText) {
            this.voiceStatusText.innerHTML = '🔒 Microphone Access Denied';
            this.voiceStatusText.style.color = '#ff6b6b';
        }
        if (this.voiceStatusSubtext) {
            this.voiceStatusSubtext.innerHTML = 
                '<a href="#" onclick="window.chatInterface.showPermissionFixInstructions(); return false;" style="color: #007bff;">Click here to fix</a>';
        }
        if (this.micBtn) {
            this.micBtn.disabled = true;
            this.micBtn.style.opacity = '0.5';
        }
    }
    
    showPermissionFixInstructions() {
        const browser = this.detectBrowser();
        alert(
            `=== FIX MICROPHONE PERMISSIONS ===\n\n` +
            `Browser: ${browser}\n\n` +
            `STEPS:\n` +
            `1. Click the 🔒 icon in address bar\n` +
            `2. Find "Microphone" permission\n` +
            `3. Change from "Block" to "Allow"\n` +
            `4. Refresh the page (F5)\n` +
            `5. Click microphone button again\n\n` +
            `Current URL: ${window.location.href}`
        );
    }
    
    detectBrowser() {
        const ua = navigator.userAgent;
        if (ua.includes('Edg')) return 'Edge';
        if (ua.includes('Chrome')) return 'Chrome';
        if (ua.includes('Firefox')) return 'Firefox';
        if (ua.includes('Safari')) return 'Safari';
        return 'Unknown';
    }
    
    updateMicrophoneStatus(mainText, subText) {
        if (this.voiceStatusText) {
            this.voiceStatusText.textContent = mainText;
            this.voiceStatusText.style.color = '';
        }
        if (this.voiceStatusSubtext) {
            this.voiceStatusSubtext.innerHTML = subText;
        }
    }
    
    showMicrophoneError(message) {
        if (this.voiceStatusText) {
            this.voiceStatusText.textContent = message;
            this.voiceStatusText.style.color = '#dc3545';
        }
        if (this.voiceStatusSubtext) {
            this.voiceStatusSubtext.textContent = 'Voice input unavailable';
        }
    }
    
    async toggleVoiceInput() {
        console.log('[Voice] toggleVoiceInput called, isRecording:', this.isRecording);
        
        if (this.isRecording) {
            await this.stopRecording();
        } else {
            await this.startRecording();
        }
    }
    
    async startRecording() {
        try {
            console.log('[Voice] === Starting recording ===');
            console.log('[Voice] Context check - this:', !!this);
            console.log('[Voice] Context check - this.mediaDevicesAPI:', !!this.mediaDevicesAPI);
            
            // ✅ CRITICAL: Get fresh API reference
            const mediaAPI = this.getMediaAPI();
            
            if (!mediaAPI) {
                throw new Error('Media API not available. Please refresh the page.');
            }
            
            console.log('[Voice] Media API obtained:', !!mediaAPI);
            console.log('[Voice] getUserMedia type:', typeof mediaAPI.getUserMedia);
            
            // Update UI
            this.updateMicrophoneStatus('Requesting microphone...', 'Please allow when prompted');
            
            // ✅ Request microphone with simple constraints
            console.log('[Voice] Calling getUserMedia...');
            const stream = await mediaAPI.getUserMedia({ audio: true });
            
            console.log('[Voice] ✅ Stream obtained!');
            console.log('[Voice] Stream active:', stream.active);
            console.log('[Voice] Audio tracks:', stream.getAudioTracks().length);
            
            if (!stream || stream.getAudioTracks().length === 0) {
                throw new Error('No audio track in stream');
            }
            
            // Determine supported mime type
            let mimeType = 'audio/webm';
            if (!MediaRecorder.isTypeSupported('audio/webm')) {
                console.warn('[Voice] audio/webm not supported');
                if (MediaRecorder.isTypeSupported('audio/webm;codecs=opus')) {
                    mimeType = 'audio/webm;codecs=opus';
                } else if (MediaRecorder.isTypeSupported('audio/ogg;codecs=opus')) {
                    mimeType = 'audio/ogg;codecs=opus';
                } else {
                    mimeType = '';
                }
            }
            
            console.log('[Voice] Using mime type:', mimeType || 'default');
            
            // Create MediaRecorder
            this.mediaRecorder = new MediaRecorder(stream, mimeType ? { mimeType } : undefined);
            this.audioChunks = [];
            
            this.mediaRecorder.ondataavailable = (event) => {
                if (event.data.size > 0) {
                    console.log('[Voice] Chunk received:', event.data.size, 'bytes');
                    this.audioChunks.push(event.data);
                }
            };
            
            this.mediaRecorder.onstop = async () => {
                console.log('[Voice] Recording stopped, chunks:', this.audioChunks.length);
                const audioBlob = new Blob(this.audioChunks, { type: mimeType || 'audio/webm' });
                console.log('[Voice] Blob size:', audioBlob.size, 'bytes');
                
                await this.transcribeAudio(audioBlob);
                
                // Stop tracks
                stream.getTracks().forEach(track => {
                    console.log('[Voice] Stopping track:', track.label);
                    track.stop();
                });
            };
            
            this.mediaRecorder.onerror = (event) => {
                console.error('[Voice] MediaRecorder error:', event.error);
            };
            
            // Start recording
            this.mediaRecorder.start();
            this.isRecording = true;
            
            // Update UI
            if (this.micBtn) {
                this.micBtn.classList.add('recording');
                this.micBtn.disabled = false;
            }
            
            this.updateMicrophoneStatus('🔴 Recording... Click to stop', 'Speak clearly');
            
            if (this.waveform) this.waveform.classList.add('active');
            
            console.log('[Voice] ✅ Recording started successfully');
            
        } catch (error) {
            console.error('[Voice] ❌ Recording error:', error);
            console.error('[Voice] Error name:', error.name);
            console.error('[Voice] Error message:', error.message);
            console.error('[Voice] Error stack:', error.stack);
            
            // Detailed diagnostics
            console.log('[Voice] === DIAGNOSTICS ===');
            console.log('[Voice] typeof navigator:', typeof navigator);
            console.log('[Voice] navigator.mediaDevices:', navigator.mediaDevices);
            console.log('[Voice] window.isSecureContext:', window.isSecureContext);
            console.log('[Voice] window.location.href:', window.location.href);
            
            let errorMessage = 'Recording failed';
            let subMessage = 'Check console for details';
            
            if (error.name === 'NotAllowedError') {
                errorMessage = '🔒 Permission Denied';
                subMessage = '<a href="#" onclick="window.chatInterface.showPermissionFixInstructions(); return false;">Fix permissions</a>';
            } else if (error.name === 'NotFoundError') {
                errorMessage = '🎤 No microphone found';
                subMessage = 'Check Device Manager';
            } else if (error.name === 'NotReadableError') {
                errorMessage = '⚠️ Microphone in use';
                subMessage = 'Close other apps';
            } else if (error.message.includes('Media API')) {
                errorMessage = '❌ API Error';
                subMessage = '<a href="#" onclick="location.reload()">Refresh page</a>';
            } else {
                errorMessage = '❌ ' + error.name;
                subMessage = error.message;
            }
            
            this.updateMicrophoneStatus(errorMessage, subMessage);
            
            // Show alert
            setTimeout(() => {
                alert(
                    `Microphone Error\n\n` +
                    `${error.name}: ${error.message}\n\n` +
                    `Troubleshooting:\n` +
                    `1. Refresh page (F5)\n` +
                    `2. Check microphone permissions in browser\n` +
                    `3. Open DevTools Console (F12) for details\n` +
                    `4. Ensure using Chrome, Edge, or Firefox\n\n` +
                    `Current URL: ${window.location.href}`
                );
            }, 300);
        }
    }
    
    async stopRecording() {
        if (this.mediaRecorder && this.isRecording) {
            console.log('[Voice] Stopping recording...');
            this.mediaRecorder.stop();
            this.isRecording = false;
            
            if (this.micBtn) this.micBtn.classList.remove('recording');
            this.updateMicrophoneStatus('Processing...', 'Transcribing audio');
            if (this.waveform) this.waveform.classList.remove('active');
        }
    }
    
    async transcribeAudio(audioBlob) {
        try {
            console.log('[Voice] Transcribing audio...', audioBlob.size, 'bytes');
            
            const formData = new FormData();
            formData.append('audio', audioBlob, 'recording.webm');
            formData.append('language', 'en');
            
            this.updateMicrophoneStatus('Transcribing...', 'Using OpenAI Whisper');
            
            const response = await fetch(`${this.voiceApiBaseUrl}/transcribe`, {
                method: 'POST',
                body: formData
            });
            
            const data = await response.json();
            
            if (data.success && data.text) {
                console.log('[Voice] ✅ Transcription:', data.text);
                
                this.messageInput.value = data.text;
                this.updateCharCount();
                
                this.updateMicrophoneStatus('✅ Complete!', 'Sending message...');
                
                setTimeout(() => {
                    this.sendMessage();
                }, 1000);
                
            } else {
                console.error('[Voice] Transcription failed:', data.error);
                this.updateMicrophoneStatus('Could not understand', 'Try again');
            }
            
            setTimeout(() => {
                if (!this.isRecording) {
                    this.updateMicrophoneStatus('Click to speak', 'Powered by OpenAI Whisper');
                }
            }, 3000);
            
        } catch (error) {
            console.error('[Voice] Transcription error:', error);
            this.updateMicrophoneStatus('Transcription failed', 'Try again');
        }
    }
    
    toggleAutoSpeak() {
        this.autoSpeak = !this.autoSpeak;
        
        if (this.autoSpeak) {
            if (this.speakerBtn) this.speakerBtn.classList.add('active');
            this.updateMicrophoneStatus('Auto-speak ON ✓', 'Responses will be read aloud');
            console.log('[Voice] ✅ Auto-speak enabled');
        } else {
            if (this.speakerBtn) this.speakerBtn.classList.remove('active');
            this.updateMicrophoneStatus('Auto-speak OFF', 'Click speaker to enable');
            console.log('[Voice] Auto-speak disabled');
            
            if (this.currentAudio) {
                this.currentAudio.pause();
                this.currentAudio = null;
            }
        }
        
        setTimeout(() => {
            if (!this.isRecording && !this.autoSpeak) {
                this.updateMicrophoneStatus('Click microphone to speak', 'Powered by OpenAI Whisper');
            }
        }, 2000);
    }
    
    async speakText(text) {
        if (!this.autoSpeak) return;
        
        try {
            console.log('[Voice] Generating speech...');
            
            const cleanText = text
                .replace(/\*\*/g, '')
                .replace(/\*/g, '')
                .replace(/#{1,6}\s/g, '')
                .replace(/`/g, '')
                .substring(0, 4000);
            
            if (this.speakerBtn) this.speakerBtn.classList.add('speaking');
            this.updateMicrophoneStatus('Generating speech...', 'Using OpenAI TTS');
            
            const response = await fetch(`${this.voiceApiBaseUrl}/speak`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    text: cleanText,
                    voice: this.selectedVoice,
                    speed: 1.0
                })
            });
            
            const data = await response.json();
            
            if (data.success && data.audio_url) {
                console.log('[Voice] ✅ Speech generated');
                
                this.currentAudio = new Audio(data.audio_url);
                
                this.currentAudio.onplay = () => {
                    this.updateMicrophoneStatus('Speaking...', 'Playing audio');
                };
                
                this.currentAudio.onended = () => {
                    if (this.speakerBtn) this.speakerBtn.classList.remove('speaking');
                    this.updateMicrophoneStatus('Auto-speak ON ✓', 'Ready');
                    this.currentAudio = null;
                };
                
                this.currentAudio.onerror = (error) => {
                    console.error('[Voice] Playback error:', error);
                    if (this.speakerBtn) this.speakerBtn.classList.remove('speaking');
                };
                
                await this.currentAudio.play();
            }
            
        } catch (error) {
            console.error('[Voice] TTS error:', error);
            if (this.speakerBtn) this.speakerBtn.classList.remove('speaking');
        }
    }
    
    // Keep your existing sendMessage function unchanged
    async sendMessage() {
        const message = this.messageInput.value.trim();
        
        if (!message || this.isWaitingForResponse) return;
        
        if (!this.conversationInitialized) {
            console.error('[UnifiedChat] No active conversation');
            this.showError('Chat not initialized. Please refresh.');
            return;
        }
        
        console.log('[UnifiedChat] Sending:', message);
        
        if (!this.firstMessageSent) {
            console.log('[UnifiedChat] First message');
            this.removeWelcomeScreen();
            
            if (this.initialGreeting) {
                this.displayMessage(this.initialGreeting.response, 'bot', this.initialGreeting.agent_type);
                this.showAgentIndicator(this.initialGreeting.agent_type);
            }
            
            this.firstMessageSent = true;
        }
        
        this.displayMessage(message, 'user');
        this.messageInput.value = '';
        this.messageInput.style.height = 'auto';
        this.updateCharCount();
        
        this.showTypingIndicator();
        this.isWaitingForResponse = true;
        this.sendButton.disabled = true;
        
        if (this.micBtn) this.micBtn.disabled = true;
        
        try {
            const response = await fetch(`${this.apiBaseUrl}/chat`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ message })
            });
            
            const data = await response.json();
            this.hideTypingIndicator();
            
            if (data.success) {
                this.currentAgentType = data.agent_type;
                this.displayMessage(data.response, 'bot', data.agent_type);
                this.showAgentIndicator(data.agent_type);
                
                if (this.autoSpeak && data.response) {
                    await this.speakText(data.response);
                }
                
                if (data.agent_type === 'event_creation' && data.event_created) {
                    this.showSuccessNotification('Event created!');
                }
            } else {
                this.displayMessage(data.response || 'Error occurred', 'bot', 'error');
            }
        } catch (error) {
            console.error('[UnifiedChat] Error:', error);
            this.hideTypingIndicator();
            this.displayMessage('Connection error', 'bot', 'error');
        } finally {
            this.isWaitingForResponse = false;
            this.sendButton.disabled = false;
            
            if (this.micBtn) this.micBtn.disabled = false;
            
            this.messageInput.focus();
        }
    }
}

// Global functions
function toggleVoiceInput() {
    console.log('[Global] toggleVoiceInput called');
    console.log('[Global] window.chatInterface exists:', !!window.chatInterface);
    
    if (window.chatInterface && typeof window.chatInterface.toggleVoiceInput === 'function') {
        window.chatInterface.toggleVoiceInput();
    } else {
        console.error('[Global] Chat interface not properly initialized');
        alert('Voice feature not ready. Please refresh the page.');
    }
}

function toggleAutoSpeak() {
    if (window.chatInterface && typeof window.chatInterface.toggleAutoSpeak === 'function') {
        window.chatInterface.toggleAutoSpeak();
    }
}

function startWithMessage(message) {
    if (window.chatInterface) {
        window.chatInterface.messageInput.value = message;
        window.chatInterface.sendMessage();
    }
}

function startVoiceMode() {
    if (window.chatInterface && window.chatInterface.toggleAutoSpeak) {
        if (!window.chatInterface.autoSpeak) {
            window.chatInterface.toggleAutoSpeak();
        }
        setTimeout(() => {
            if (window.chatInterface.toggleVoiceInput) {
                window.chatInterface.toggleVoiceInput();
            }
        }, 500);
    }
}
