async function checkAgentStatus() {
    try {
        const response = await fetch('/api/agent/status');
        const data = await response.json();
        alert(`Agent Status:\n${JSON.stringify(data, null, 2)}`);
        return data;
    } catch (error) {
        console.error('[Global] Status error:', error);
        return null;
    }
}

