    console.log('[Global] === Initializing Unified Chat ===');
    console.log('[Global] Checking environment...');
    console.log('[Global] navigator:', typeof navigator);
    console.log('[Global] navigator.mediaDevices:', !!navigator.mediaDevices);
    console.log('[Global] getUserMedia:', !!navigator.mediaDevices?.getUserMedia);
    console.log('[Global] Secure context:', window.isSecureContext);
    console.log('[Global] Location:', window.location.href);
    
